import{_ as a}from"./chunks/文件受限图.DsG20F9s.js";import{_ as i,o as l,c as t,a2 as d}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"Image Moderation و Access Mode","description":"","frontmatter":{},"headers":[],"relativePath":"fa/Safety/image-moderation-and-access-mode.md","filePath":"fa/Safety/image-moderation-and-access-mode.md","lastUpdated":1781962217000}'),r={name:"fa/Safety/image-moderation-and-access-mode.md"};function o(s,e,n,c,m,p){return l(),t("div",null,[...e[0]||(e[0]=[d('<h1 id="image-moderation-و-access-mode" tabindex="-1">Image Moderation و Access Mode <a class="header-anchor" href="#image-moderation-و-access-mode" aria-label="Permalink to &quot;Image Moderation و Access Mode&quot;">​</a></h1><p>Image moderation به uploaded images، age rating اختصاص می‌دهد. Access mode مشخص می‌کند کدام ratings از طریق public access قابل مشاهده باشند.</p><p>این تنظیم روی public gallery، public file URLs و random image API اثر دارد. admin panel را محدود نمی‌کند. Administrators همچنان می‌توانند همه files را ببینند و مدیریت کنند.</p><h2 id="کجا-configure-کنیم" tabindex="-1">کجا Configure کنیم <a class="header-anchor" href="#کجا-configure-کنیم" aria-label="Permalink to &quot;کجا Configure کنیم&quot;">​</a></h2><p>admin panel را باز کنید و بروید به:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; Image Moderation</span></span></code></pre></div><p>تنظیمات اصلی:</p><ul><li>Access mode</li><li>Enable moderation</li><li>Moderation provider</li></ul><h2 id="access-mode-چه-می‌کند" tabindex="-1">Access Mode چه می‌کند <a class="header-anchor" href="#access-mode-چه-می‌کند" aria-label="Permalink to &quot;Access Mode چه می‌کند&quot;">​</a></h2><p>Access mode مشخص می‌کند کدام age ratings به‌صورت public نمایش داده شوند.</p><p>modeهای فعلی:</p><table tabindex="0"><thead><tr><th>Access Mode</th><th>Publicly Visible Ratings</th></tr></thead><tbody><tr><td>Adult mode</td><td>General, R12, R16, R18</td></tr><tr><td>Youth mode</td><td>General, R12, R16</td></tr><tr><td>Teen mode</td><td>General, R12</td></tr><tr><td>Child mode</td><td>فقط General</td></tr></tbody></table><p>پیش‌فرض Adult mode است.</p><p>برای private sites یا سایت‌هایی با mature content، Adult mode ممکن است مناسب باشد. برای public gallery محافظه‌کارانه‌تر، Youth، Teen یا Child mode را انتخاب کنید.</p><h2 id="enable-کردن-moderation-چه-اثری-دارد" tabindex="-1">Enable کردن Moderation چه اثری دارد <a class="header-anchor" href="#enable-کردن-moderation-چه-اثری-دارد" aria-label="Permalink to &quot;Enable کردن Moderation چه اثری دارد&quot;">​</a></h2><p>وقتی moderation enabled باشد، ImgBed هنگام upload، moderation provider انتخاب‌شده را call می‌کند و detected age rating را ذخیره می‌کند.</p><p>ratings اصلی:</p><table tabindex="0"><thead><tr><th>Rating</th><th>Meaning</th></tr></thead><tbody><tr><td>General</td><td>محتوای امن برای public</td></tr><tr><td>R12</td><td>محتوای کمی حساس</td></tr><tr><td>R16</td><td>محتوای نسبتاً حساس</td></tr><tr><td>R18</td><td>محتوای adult</td></tr></tbody></table><p>moderation result هنگام تصمیم‌گیری برای public access استفاده می‌شود.</p><p>اگر moderation enabled نباشد، یا old files rating نداشته باشند، آن files به‌عنوان unrated در نظر گرفته می‌شوند. unrated files فقط به دلیل نداشتن rating به‌صورت خودکار از public gallery یا random image API حذف نمی‌شوند.</p><h2 id="انتخاب-moderation-provider" tabindex="-1">انتخاب Moderation Provider <a class="header-anchor" href="#انتخاب-moderation-provider" aria-label="Permalink to &quot;انتخاب Moderation Provider&quot;">​</a></h2><p>providers موجود:</p><ul><li>moderatecontent.com</li><li>nsfwjs</li><li>Sightengine</li></ul><p>هر provider requirement متفاوتی دارد:</p><ul><li>moderatecontent.com معمولاً API Key لازم دارد.</li><li>nsfwjs معمولاً API endpoint URL لازم دارد.</li><li>Sightengine به API user و API secret نیاز دارد.</li></ul><p>بر اساس account، availability و detection quality انتخاب کنید. وقتی moderation enabled و درست configured باشد، ImgBed هنگام upload تلاش می‌کند image rating را بنویسد.</p><h2 id="اثر-روی-public-gallery" tabindex="-1">اثر روی Public Gallery <a class="header-anchor" href="#اثر-روی-public-gallery" aria-label="Permalink to &quot;اثر روی Public Gallery&quot;">​</a></h2><p>public gallery، files را بر اساس access mode filter می‌کند.</p><p>مثال‌ها:</p><ul><li>Adult mode: R18 images می‌توانند ظاهر شوند.</li><li>Youth mode: R18 images پنهان می‌شوند.</li><li>Teen mode: R16 و R18 images پنهان می‌شوند.</li><li>Child mode: فقط General images نمایش داده می‌شود.</li></ul><p>این فقط normal public access را تحت تأثیر قرار می‌دهد. admin panel همچنان همه files را نشان می‌دهد.</p><h2 id="اثر-روی-public-file-urls" tabindex="-1">اثر روی Public File URLs <a class="header-anchor" href="#اثر-روی-public-file-urls" aria-label="Permalink to &quot;اثر روی Public File URLs&quot;">​</a></h2><p>Public file URLs همان direct image links هستند که visitors باز می‌کنند.</p><p>اگر file rating در current access mode مجاز باشد، ImgBed original image را برمی‌گرداند.</p><p>اگر rating بالاتر از سطح مجاز باشد، normal public access original image را برنمی‌گرداند. در عوض ImgBed configured blocked result یا تصویر جایگزین blocked را برمی‌گرداند.</p><p>مثال:</p><ul><li>current mode برابر Child mode است.</li><li>یک image با R18 rated شده.</li><li>visitor public URL را مستقیم باز می‌کند.</li><li>ImgBed original image R18 را به آن visitor برنمی‌گرداند.</li></ul><p><img src="'+a+'" alt="Restricted file image" loading="lazy"></p><p>Administrators که files را در admin panel می‌بینند، تحت تأثیر این محدودیت نیستند.</p><h2 id="اثر-روی-random-image-api" tabindex="-1">اثر روی Random Image API <a class="header-anchor" href="#اثر-روی-random-image-api" aria-label="Permalink to &quot;اثر روی Random Image API&quot;">​</a></h2><p>random image API هم candidate pool خود را بر اساس access mode filter می‌کند.</p><p>در Child mode، random images فقط از General-rated files انتخاب می‌شوند.</p><p>در Youth mode، random images می‌توانند از General، R12 و R16 باشند، اما R18 نه.</p><p>این باعث می‌شود random image API نتواند public gallery restrictions را دور بزند.</p><h2 id="ارتباط-با-list-rules" tabindex="-1">ارتباط با List Rules <a class="header-anchor" href="#ارتباط-با-list-rules" aria-label="Permalink to &quot;ارتباط با List Rules&quot;">​</a></h2><p>Access mode تنها public access rule نیست. همراه با allow/block list rules کار می‌کند.</p><p>به‌صورت ساده:</p><ul><li>Allowlisted content ابتدا public محسوب می‌شود.</li><li>Blocklisted content برای regular visitors مستقیم قابل مشاهده نیست.</li><li>محتوایی که در هیچ‌کدام نیست، سپس با access mode بررسی می‌شود.</li></ul><p>اگر image هم با age rating و هم با list rules restricted باشد، regular visitors همچنان نمی‌توانند original file را مستقیم ببینند.</p><h2 id="recommended-settings" tabindex="-1">Recommended Settings <a class="header-anchor" href="#recommended-settings" aria-label="Permalink to &quot;Recommended Settings&quot;">​</a></h2><p>برای public sites:</p><ul><li>moderation را enable کنید.</li><li>access mode مناسب با audience سایت را انتخاب کنید.</li><li>برای all-age visitors از Child mode یا Teen mode استفاده کنید.</li><li>اگر نمی‌خواهید mature content عمومی نمایش داده شود، از Adult mode پرهیز کنید.</li><li>file ratings را در admin panel review کنید و در صورت نیاز دستی adjust کنید.</li></ul><p>برای private یا personal sites:</p><ul><li>Adult mode معمولاً مشکلی ندارد.</li><li>اگر مفید است moderation را enable کنید.</li><li>ratings را در admin panel review و adjust کنید.</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="بعد-از-تغییر-access-mode،-files-از-admin-panel-حذف-می‌شوند؟" tabindex="-1">بعد از تغییر Access Mode، files از Admin Panel حذف می‌شوند؟ <a class="header-anchor" href="#بعد-از-تغییر-access-mode،-files-از-admin-panel-حذف-می‌شوند؟" aria-label="Permalink to &quot;بعد از تغییر Access Mode، files از Admin Panel حذف می‌شوند؟&quot;">​</a></h3><p>خیر.</p><p>Access mode فقط normal public access را تحت تأثیر قرار می‌دهد. admin panel تحت تأثیر نیست.</p><h3 id="چرا-بعد-از-رفتن-به-child-mode،-public-gallery-تصاویر-کمتری-نشان-می‌دهد؟" tabindex="-1">چرا بعد از رفتن به Child Mode، Public Gallery تصاویر کمتری نشان می‌دهد؟ <a class="header-anchor" href="#چرا-بعد-از-رفتن-به-child-mode،-public-gallery-تصاویر-کمتری-نشان-می‌دهد؟" aria-label="Permalink to &quot;چرا بعد از رفتن به Child Mode، Public Gallery تصاویر کمتری نشان می‌دهد؟&quot;">​</a></h3><p>Child mode فقط General-rated files را public نشان می‌دهد. R12، R16 و R18 filter می‌شوند.</p><h3 id="آیا-public-urls-هنوز-adult-images-را-باز-می‌کنند؟" tabindex="-1">آیا Public URLs هنوز Adult Images را باز می‌کنند؟ <a class="header-anchor" href="#آیا-public-urls-هنوز-adult-images-را-باز-می‌کنند؟" aria-label="Permalink to &quot;آیا Public URLs هنوز Adult Images را باز می‌کنند؟&quot;">​</a></h3><p>اگر current access mode آن rating را allow نکند، normal public URLs original image را برنمی‌گردانند.</p><h3 id="آیا-random-image-api-می‌تواند-restricted-images-برگرداند؟" tabindex="-1">آیا Random Image API می‌تواند Restricted Images برگرداند؟ <a class="header-anchor" href="#آیا-random-image-api-می‌تواند-restricted-images-برگرداند؟" aria-label="Permalink to &quot;آیا Random Image API می‌تواند Restricted Images برگرداند؟&quot;">​</a></h3><p>خیر.</p><p>random image API candidates را بر اساس current access mode filter می‌کند.</p><h3 id="old-unrated-images-چه-می‌شوند؟" tabindex="-1">Old Unrated Images چه می‌شوند؟ <a class="header-anchor" href="#old-unrated-images-چه-می‌شوند؟" aria-label="Permalink to &quot;Old Unrated Images چه می‌شوند؟&quot;">​</a></h3><p>unrated images فقط به دلیل نداشتن moderation results به‌صورت خودکار hidden نمی‌شوند. می‌توانید بعداً ratings آن‌ها را در admin panel adjust کنید.</p>',67)])])}const b=i(r,[["render",o]]);export{h as __pageData,b as default};
